import{_ as e,c as s,a2 as t,o as n}from"./chunks/framework.Dtz5kk4D.js";const u=JSON.parse('{"title":"Database","description":"Database is a collection of data that is stored and organized in a way that can be easily accessed, managed and updated.","frontmatter":{"title":"Database","description":"Database is a collection of data that is stored and organized in a way that can be easily accessed, managed and updated.","date":"2024-10-20T00:00:00.000Z","lastmod":"2024-10-29T00:00:00.000Z"},"headers":[],"relativePath":"Concepts/Database/index.md","filePath":"Concepts/Database/README.md","lastUpdated":null}'),i={name:"Concepts/Database/index.md"};function l(o,a,r,p,d,c){return n(),s("div",null,a[0]||(a[0]=[t(`<h1 id="database" tabindex="-1">Database <a class="header-anchor" href="#database" aria-label="Permalink to &quot;Database&quot;">​</a></h1><p>A <strong>database</strong> is a collection of data that is stored and organized in a way that can be easily accessed, managed and updated. Databases are used to store and manage data for various applications, such as websites, mobile apps, and desktop software</p><ul><li><p>A <em>database</em> is nothing more than a set of related information</p></li><li><p>A <em>database management system (DBMS)</em> is a software that allows users to define, create, maintain and control access to the database</p><ul><li>Primary goal of a DBMS is to provide an <em>efficient</em> and <em>convenient</em> method for defining and managing databases</li></ul></li></ul><h2 id="non-relational-database-systems" tabindex="-1">Non-Relational Database Systems <a class="header-anchor" href="#non-relational-database-systems" aria-label="Permalink to &quot;Non-Relational Database Systems&quot;">​</a></h2><p>Databases before the advent of relational databases were non-relational. They were based on the hierarchical or network model. These databases were designed to handle specific types of data and were not as flexible as relational databases</p><ul><li><p><strong>Hierarchical Database</strong>: Data is organized in a tree-like structure, with parent-child relationships</p><ul><li><em>Single-parent</em> hierarchy (one-to-many relationship)</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes ayu-dark ayu-dark vp-code" tabindex="0"><code><span class="line"><span>  Company</span></span>
<span class="line"><span>   /    \\</span></span>
<span class="line"><span>  Dept1  Dept2</span></span>
<span class="line"><span> /    \\   |   \\</span></span>
<span class="line"><span>Emp1 Emp2 Emp3 Emp4</span></span></code></pre></div></li><li><p><strong>Network Database</strong>: Data is organized in a graph-like structure, with many-to-many relationships</p><ul><li>Exposes sets of records and sets of links that define relationships between different records</li><li><em>Multiple-parent</em> hierarchy (many-to-many relationship)</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes ayu-dark ayu-dark vp-code" tabindex="0"><code><span class="line"><span>Employee1</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>Project1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Employee2</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>Project2</span></span></code></pre></div></li></ul><h2 id="relational-database-systems" tabindex="-1">Relational Database Systems <a class="header-anchor" href="#relational-database-systems" aria-label="Permalink to &quot;Relational Database Systems&quot;">​</a></h2><p>A <strong>relational database</strong> is a type of database that stores and provides access to data points that are related to one another</p><p>The relational database model was introduced by <strong>E.F. Codd in 1970</strong> of IBM&#39;s research laboratory</p><ul><li>Published a paper titled <strong>&quot;A Relational Model of Data for Large Shared Data Banks&quot;</strong></li><li>It is based on the concept of tables, where data is stored in rows and columns</li><li>Rather than using pointers to navigate between related entities, redundant data is used to link related records in different tables</li><li>The data can be accessed or reassembled in many different ways without having to reorganize the database tables</li></ul><h3 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h3><ul><li><strong>Table</strong>: A table is a collection of data organized into rows and columns</li><li><strong>Column</strong>: A column is a set of data values of a particular type</li><li><strong>Row</strong>: A row is a single record in a table</li><li><strong>Primary Key</strong>: A primary key is a unique identifier for each row in a table</li><li><strong>Foreign Key</strong>: A foreign key is a column that references a primary key in another table</li><li><strong>Index</strong>: An index is a data structure that improves the speed of data retrieval operations on a database table</li><li><strong>View</strong>: A view is a virtual table that is based on the result of a SELECT query</li><li><strong>Transaction</strong>: A transaction is a single unit of work that is performed on a database</li></ul><h3 id="types-of-relationships" tabindex="-1">Types of Relationships <a class="header-anchor" href="#types-of-relationships" aria-label="Permalink to &quot;Types of Relationships&quot;">​</a></h3><ol><li><p><strong>One-to-One Relationship</strong>: A relationship where each record in one table is related to only one record in another table</p><ul><li>Example: A person has only one passport</li></ul></li><li><p><strong>One-to-Many Relationship</strong>: A relationship where each record in one table is related to one or more records in another table</p><ul><li>Example: A customer can have multiple orders</li></ul></li><li><p><strong>Many-to-Many Relationship</strong>: A relationship where each record in one table is related to one or more records in another table, and vice versa</p><ul><li>Example: A student can enrol in multiple courses, and a course can have multiple students</li></ul></li></ol><h2 id="data-models" tabindex="-1">Data Models <a class="header-anchor" href="#data-models" aria-label="Permalink to &quot;Data Models&quot;">​</a></h2><p>A <strong>data model</strong> is a conceptual representation of the data structures that are required by a database</p><ol><li><p><strong>Entity-Relationship Model</strong>: A data model that describes the relationships between entities in a database</p><ul><li>The entity-relationship (E-R) data model uses a collection of basic objects, called <em>entities</em>, and <em>relationships</em> among these objects</li><li>An entity is a &quot;thing&quot; or &quot;object&quot; in the real world that is distinguishable from other objects</li></ul></li><li><p><strong>Relational Model</strong>: A data model that describes the relationships between tables in a database</p><ul><li>The relational model uses a collection of tables to represent both data and the relationships among those data</li><li>Each table has multiple columns, and each column has a unique name</li><li>Tables are also known as <strong>relations</strong></li></ul></li><li><p><strong>Semi-Structured Model</strong>: A data model that allows for the representation of data that does not fit neatly into a tabular format</p><ul><li>This data model permits the specification of data where individual data items of the same type may have different attributes</li><li><em>JSON</em> and <em>XML</em> are examples of semi-structured data formats</li></ul></li><li><p><strong>Object-Oriented Model</strong>: A data model that represents data as objects, similar to object-oriented programming</p></li></ol><h3 id="relational-data-model" tabindex="-1">Relational Data Model <a class="header-anchor" href="#relational-data-model" aria-label="Permalink to &quot;Relational Data Model&quot;">​</a></h3><p>Data are represented in the form of tables</p><ul><li>Each table has multiple columns, and each column has a unique name</li><li>Each row in a table represents one piece of information (one record)</li></ul><h3 id="data-abstraction" tabindex="-1">Data Abstraction <a class="header-anchor" href="#data-abstraction" aria-label="Permalink to &quot;Data Abstraction&quot;">​</a></h3><p><strong>Data abstraction</strong> is the process of hiding the complex details of data storage and retrieval operations</p><p>Different levels of data abstraction:</p><ul><li><p><strong>Physical Level</strong>: Describes how data is stored in the database (e.g., data structures, file formats)</p><ul><li>Lowest level of abstraction</li></ul></li><li><p><strong>Logical Level</strong>: Describes <strong>what</strong> data is stored in the database and the relationships among the data</p><ul><li>Describes the structure of the database</li><li>Independent of the physical storage of data (physical data independence)</li></ul></li><li><p><strong>View Level</strong>: Describes <strong>how</strong> data is presented to the user</p><ul><li>Highest level of abstraction</li><li>Describes only a part of the database</li><li>Not all users need to see all the data in the database</li></ul></li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes ayu-dark ayu-dark vp-code" tabindex="0"><code><span class="line"><span>+------------------------------------+</span></span>
<span class="line"><span>|            View Level              |</span></span>
<span class="line"><span>|                                    |</span></span>
<span class="line"><span>| View 1  View 2  View 3  ... View n |</span></span>
<span class="line"><span>|                                    |</span></span>
<span class="line"><span>+------------------------------------+</span></span>
<span class="line"><span>                 |</span></span>
<span class="line"><span>                 |</span></span>
<span class="line"><span></span></span>
<span class="line"><span>           Logical Level</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                 |</span></span>
<span class="line"><span>                 |</span></span>
<span class="line"><span></span></span>
<span class="line"><span>          Physical Level</span></span></code></pre></div><h2 id="database-paradigms" tabindex="-1">Database Paradigms <a class="header-anchor" href="#database-paradigms" aria-label="Permalink to &quot;Database Paradigms&quot;">​</a></h2><ol><li><p>Key-value: Redis, Memcache, etc.</p><ul><li>Caching</li><li>Pub/Sub</li><li>Leaderboards</li></ul></li><li><p>Wide Column: Apache Cassandra, Apache HBase</p><ul><li>Time-series</li><li>Historical Records</li><li>High-write, low-read</li></ul></li><li><p>Document: MongoDB, Firebase Database, Amazon DynamoDB, Apache CouchDB</p><ul><li>Most Apps</li><li>Games</li><li>IOT</li></ul></li><li><p>RDBMS: MySQL, PostgreSQL, SQL Server, CockroachDB</p><ul><li>Most Apps</li><li>Not ideal for unstructured data</li></ul></li><li><p>Graph: Neo4j, Dgraph</p><ul><li>Graphs</li><li>Knowledge Graphs</li><li>Recommendation Engines</li></ul></li><li><p>Search: Apache Lucene, Elasticsearch, Apache Solr, Algolia, meilisearch</p><ul><li>Search Engines</li><li>Typeahead</li></ul></li><li><p>Multi-Model: Fauna</p></li></ol><h2 id="popular-database-management-systems-dbms" tabindex="-1">Popular Database Management Systems (DBMS) <a class="header-anchor" href="#popular-database-management-systems-dbms" aria-label="Permalink to &quot;Popular Database Management Systems (DBMS)&quot;">​</a></h2><ol><li><a href="./SQLite.html">SQLite</a></li><li><a href="./MySQL.html">MySQL</a></li><li><a href="./PostgreSQL.html">PostgreSQL</a></li><li><a href="./MongoDB/MongoDB.html">MongoDB</a></li><li><a href="./MongoDB/MongoDB_Udemy.html">MongoDB Udemy</a></li><li><a href="./Redis.html">Redis</a></li><li>Oracle Database</li><li>Microsoft SQL Server</li></ol><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>CODASYL (Conference/Committee on Data Systems Languages)</li><li>Hierarchical</li></ul>`,31)]))}const m=e(i,[["render",l]]);export{u as __pageData,m as default};
